const $=(s,r=document)=>r.querySelector(s);
const state={route:"map",context:"Wild",visibility:"Private",collection:"All",rank:"Friends",profile:"Grid",group:"Feed",notif:"All",joined:false,welfare:false,reactions:{Wow:false,Cute:false,Rare:false,"Safe Shot":false},likes:128};
const nav=[["map","Map","Map"],["capture","Capture","Cap"],["feed","Feed","Feed"],["collection","Guide","Guide"],["rank","Rank","Rank"]];
const animals=[["House Sparrow","Urban - Common","Islamabad area",12,"bird"],["Indian Peafowl","Park - Common","Park zone",44,"peacock"],["Plain Tiger","Garden - Common","Islamabad area",18,"butterfly"]];
const species=[["Common Kingfisher","Rare","62 pts","Wild","king"],["Golden Eagle","Rare wild","75 pts","Wild","eagle"],["Golden Retriever","Friendly","Pet shelf","Pet","dog"],["Indian Peafowl","Common","44 pts","Zoo","peacock"],["Common Myna","Urban","21 pts","Wild","bird"],["Water habitat","Missing card","Keep exploring","Rare","locked"]];
const notices=[["Game","Score Revealed","Golden Eagle earned 75 pts.","2m","Open","score","eagle"],["Social","Friend Liked Your Capture","nature_traveler reacted Safe Shot.","8m","Reply","feed","bird"],["Game","Group Quest Complete","Islamabad Wildlife Squad unlocked a badge.","12m","View","group","peacock"],["Game pending","Scoring In Progress","Your bulbul photo is being reviewed.","20m","Track","capture","bulbul"],["Safety","Report Resolved","Thanks for helping keep the feed safe.","1h","Done","",""]];
const leaders={Friends:[["1","Mina","Ranger III","4,910 pts","42 subs"],["2","Omar","Bird Watcher","4,420 pts","38 subs"],["128","You","Ranger II","2,865 pts","27 subs"]],Local:[["1","Ayesha","Park Scout","5,140 pts","48 subs"],["2","You","Ranger II","2,865 pts","27 subs"],["3","Zain","Safe Shot","2,710 pts","25 subs"]],Country:[["1","Mina","Ranger III","9,910 pts","88 subs"],["128","You","Ranger II","2,865 pts","27 subs"]],Global:[["1","Ria","World Ranger","18,400 pts","140 subs"],["1280","You","Ranger II","2,865 pts","27 subs"]]};
function routeTo(route){state.route=route;location.hash=route;render();}
function toast(msg){const t=$("#toast");t.textContent=msg;t.classList.add("show");clearTimeout(toast.timer);toast.timer=setTimeout(()=>t.classList.remove("show"),1900);}
function modal(title,body,actions=`<button data-modal-close>Cancel</button><button class="primary" data-modal-ok>Submit</button>`){$("#modal").innerHTML=`<section class="modal-card"><h2>${title}</h2>${body}<div class="actions">${actions}</div></section>`;$("#modal").classList.add("open");$("#modal").setAttribute("aria-hidden","false");}
function closeModal(){const m=$("#modal");m.classList.remove("open");m.setAttribute("aria-hidden","true");}
function shell(title,sub,actions=""){return `<header class="topbar"><div><h1 class="title">${title}</h1><span class="subtle">${sub}</span></div>${actions}</header>`;}
function chips(items,active,key){return `<div class="chips">${items.map(x=>`<button class="chip ${x===active?"active":""}" data-set="${key}" data-value="${x}">${x}</button>`).join("")}</div>`;}
function tabs(items,active,key){return `<div class="tabs">${items.map(x=>`<button class="tab ${x===active?"active":""}" data-set="${key}" data-value="${x}">${x}</button>`).join("")}</div>`;}
function renderBottom(){ $("#bottomNav").innerHTML=nav.map(([r,l,i])=>`<button class="nav-btn ${state.route===r?"active":""}" data-route="${r}"><b>${i}</b><span>${l}</span></button>`).join("");}
function render(){const map={map:renderMap,capture:renderCapture,score:renderScore,feed:renderFeed,profile:renderProfile,group:renderGroup,notifications:renderNotifications,collection:renderCollection,rank:renderRank,empty:renderEmpty};$("#screen").innerHTML=(map[state.route]||renderMap)();$("#screen").dataset.route=state.route;renderBottom();}
function renderMap(){return `<header class="hud"><button class="avatar" data-route="profile">A<span class="level-pill">23</span></button><div><b>7 day streak</b><span class="subtle">Safe explorer</span></div><div class="brand">PakimonGO</div><button class="icon-btn" data-route="notifications">Bell<span class="badge">3</span></button><button class="icon-btn" data-route="profile">Me</button></header><section class="mission"><i class="mission-icon">Leaf</i><div><b>Find a bird near a park</b><span class="subtle">1/1 complete - 2 safe sightings nearby</span><div class="progress"><span></span></div></div><button data-route="empty">!</button></section><section class="map-world"><i class="road r1"></i><i class="road r2"></i><i class="road r3"></i><b class="zone z1">3</b><b class="zone z2">6</b><b class="zone z3">2</b><span class="map-label l1">near green hills</span><span class="map-label l2">safe area hidden</span><button class="capture-float" data-route="capture">Cam</button></section><section class="activity-sheet"><div class="grip"></div><h2>Nearby Activity</h2>${animals.map(a=>`<div class="activity"><span class="photo thumb ${a[4]}"></span><div><b>${a[0]}</b><small>${a[1]}</small><small>${a[2]}</small></div><strong>${a[3]} pts</strong></div>`).join("")}</section>`;}
function renderCapture(){return `${shell("Capture Review","Photo first, safety always",'<button data-action="draft">Save Draft</button>')}<section class="photo hero-photo bulbul"><span class="photo-chip">Likely 20-45 pts</span><div class="media-actions"><span>1/1</span><span>Private GPS</span></div><strong>Red-vented Bulbul</strong></section><div class="tip-card"><b>Safety check</b><span class="subtle">Submit only if you kept distance and did not disturb the animal.</span></div>${chips(["Wild","Pet","Zoo","Unsure"],state.context,"context")}<section class="field-panel"><label>Species guess<input value="Red-vented Bulbul"></label><label>Cute name<input value="Rafi"></label><label>Caption<textarea>Perched near the morning path.</textarea></label><label>Hashtags<input value="#urbanbird #safeShot #Islamabad"></label></section>${chips(["Private","Friends","Public"],state.visibility,"visibility")}<button class="chip ${state.welfare?"active":""}" data-action="welfare">Welfare concern: ${state.welfare?"On":"Off"}</button><p class="subtle">Location saved privately. Public cards show only Islamabad area.</p><div class="safe-grid"><span>No chasing</span><span>No touching</span><span>Keep distance</span></div><button class="primary" data-route="score">Submit for Score Reveal</button>`;}
function renderScore(){return `${shell("Rare Safe Shot!","Server-scored result")}<section class="photo hero-photo eagle"><span class="photo-chip">Wild</span><div class="media-actions"><span>Scored</span><span>New entry</span></div><strong>Golden Eagle</strong></section><div class="chips"><span class="chip active">Wild</span><span class="chip active">Scored</span><span class="chip active">New Collection Entry</span></div><section class="score-card"><span>Total Score</span><strong>75 pts</strong><span class="subtle">Exact location hidden</span></section><div class="breakdown">${[["Rarity","+35"],["Safety","+15"],["Aesthetic","+10"],["Name","+5"],["Novelty","+10"]].map(x=>`<div><b>${x[1]}</b><span>${x[0]}</span></div>`).join("")}</div><div class="actions"><button class="primary" data-action="share">Share Card</button><button data-route="collection">View Collection</button><button data-action="appeal">Appeal</button></div><p class="subtle">Zoo, pet, and social points are capped for fairness.</p>`;}
function renderFeed(){return `${shell("Field Stories","Friends and safe local highlights",'<button data-route="profile">Profile</button>')}<div class="stories">${["bird","peacock","dog","butterfly"].map(c=>`<button class="story photo ${c}" data-action="story"></button>`).join("")}</div><article class="post"><div class="post-head"><span class="avatar sm">N</span><div><b>nature_traveler</b><small>Friends - Islamabad area</small></div><strong>75 pts</strong></div><div class="photo feed-photo bird"><span class="photo-chip">Friends</span><div class="media-actions"><span>Safe area</span><span>Report</span></div><strong>House Sparrow</strong></div><p>Clean safe shot from a garden walk. Loved the morning light.</p><div class="tags"><span>#safeShot</span><span>#birds</span><span>#garden</span></div><div class="reactions">${Object.keys(state.reactions).map(r=>`<button class="${state.reactions[r]?"active":""}" data-react="${r}">${r}</button>`).join("")}</div><div class="social-actions">${["Like","Comment","Repost","Share","Report"].map(a=>`<button data-action="${a.toLowerCase()}">${a}</button>`).join("")}</div></article><p class="subtle">Exact locations and sensitive species are hidden by default.</p>`;}
function renderProfile(){return `<section class="profile-head"><span class="avatar">A</span><div><h1 class="title">seed_user_alpha</h1><span class="subtle">Lvl 22 - trusted safe observer</span></div><button data-action="settings">Gear</button></section><div class="stat-row"><div class="stat"><b>7,860</b><span>points</span></div><div class="stat"><b>28</b><span>streak</span></div><div class="stat"><b>#128</b><span>rank</span></div></div><h3>Pinned Captures</h3><div class="grid3">${["eagle","peacock","bird"].map((c,i)=>`<div class="photo pin ${c}"><b>${[75,44,12][i]} pts</b></div>`).join("")}</div><div class="badge-row"><span>Bird Watcher</span><span>Garden Guardian</span><span>Safe Shot</span></div>${tabs(["Grid","Collections","Stories","Stats"],state.profile,"profile")}<div class="photo-grid">${["bird","bulbul","king","peacock"].map(c=>`<div class="photo grid-photo ${c}"><b>Private</b></div>`).join("")}</div>`;}
function renderGroup(){let content=state.group==="Quests"?`<section class="quest-row"><div><b>Garden Guardians</b><span class="subtle">12/20 respectful-distance captures</span></div><button data-action="joinQuest">Join</button></section><section class="quest-row"><div><b>Water Habitat Weekend</b><span class="subtle">General park zones only</span></div><button data-action="joinQuest">Join</button></section>`:`<section class="quest-row"><div><b>Park Birds Week</b><span class="subtle">18/30 safe captures</span></div><button data-action="joinQuest">Join</button></section><article class="post"><div class="post-head"><span class="avatar sm">M</span><div><b>moderator_mina</b><small>Group visible - Islamabad area</small></div><button data-action="menu">More</button></div><div class="photo feed-photo peacock"><strong>Indian Peafowl</strong></div><div class="social-actions"><button data-action="wow">Wow</button><button data-action="comment">Comment</button><button data-action="share">Share</button><button data-action="report">Report</button><button data-action="block">Block</button></div></article><div id="postMenu" class="menu"><button data-action="report">Report Post</button><button data-action="block">Block User</button><button data-action="mute">Mute User</button></div>`;return `<section class="group-head"><span class="avatar">IW</span><div><h1 class="title">Islamabad Wildlife Squad</h1><span class="subtle">128 members - public group</span></div><button data-action="join">${state.joined?"Joined":"Invite"}</button></section><div class="stat-row"><div class="stat"><b>12.4k</b><span>weekly pts</span></div><div class="stat"><b>8</b><span>quests</span></div><div class="stat"><b>36</b><span>captures</span></div></div>${tabs(["Feed","Quests","Members","Leaderboard"],state.group,"group")}${content}`;}
function renderNotifications(){let cats=["All","Social","Game","Safety"];let rows=notices.filter(n=>state.notif==="All"||n[0].includes(state.notif));return `${shell("Activity","Social, game, updates, and safety")}<div class="chips">${cats.map(c=>`<button class="chip ${state.notif===c?"active":""}" data-set="notif" data-value="${c}">${c}</button>`).join("")}</div>${rows.map(n=>`<section class="notice ${n[0].toLowerCase().includes("pending")?"pending":n[0].toLowerCase()}">${n[6]?`<span class="photo ${n[6]}"></span>`:"<i></i>"}<div><b>${n[1]}</b><span>${n[2]}</span><span>${n[3]}</span></div><button ${n[5]?`data-route="${n[5]}"`:"data-action='done'"}>${n[4]}</button></section>`).join("")}`;}
function renderCollection(){let rows=species.filter(s=>state.collection==="All"||s[3]===state.collection||s[1].includes(state.collection));return `${shell("My Field Guide","Collectible species album")}<div class="ring-row">${[["63%","Birds"],["41%","Pets"],["22%","Zoo"],["18%","Rare"]].map(r=>`<div class="ring"><b>${r[0]}</b><span>${r[1]}</span></div>`).join("")}</div><div class="filters">${tabs(["All","Wild","Pet","Zoo","Rare","Private"],state.collection,"collection")}</div><div class="species-grid">${rows.map(s=>`<section class="species photo ${s[4]}"><b>${s[0]}</b><span>${s[1]} - ${s[2]}</span><small>${s[3]} - safe area hidden</small></section>`).join("")}</div>`;}
function renderRank(){let rows=leaders[state.rank]||leaders.Friends;return `${shell("Wild Chronicles","Season 2 - 6 days left")}<section class="season"><span>Ranger II</span><strong>#128</strong><p>2,865 pts - up 12 today</p><div class="meter"><span></span></div></section>${tabs(["Friends","Local","Country","Global"],state.rank,"rank")}<section class="card">${rows.map((l,i)=>`<div class="leader-row ${l[1]==="You"?"me":""}"><b>${l[0]}</b><span class="avatar sm">${l[1][0]}</span><div><b>${l[1]}</b><span class="subtle">${l[2]}</span></div><div><b>${l[3]}</b><span class="subtle">${l[4]}</span></div></div>`).join("")}</section><p class="subtle">Zoo, pet, and social points are capped for fairness.</p><div class="mission-stack"><section class="card"><b>Weekly Challenge</b><span class="subtle">3 park birds</span></section><section class="card"><b>Comeback Mission</b><span class="subtle">+120 possible</span></section><section class="card"><b>Safe Shot Showcase</b><span class="subtle">Enter one capture</span></section></div>`;}
function renderEmpty(){return `${shell("PakimonGO V2","Offline-safe fallback")}<div class="empty-art"></div><section class="empty-panel"><h1>Trail went quiet</h1><p>We could not load this yet. Your captures are safe.</p><div class="actions"><button class="primary" data-route="map">Retry</button><button data-action="offline">Offline Mode</button></div></section><div class="trust"><div><b>Your data is private</b><span class="subtle">Precise locations stay protected.</span></div><div><b>Safety first</b><span class="subtle">No score is worth disturbing wildlife.</span></div><div><b>Nothing lost</b><span class="subtle">Drafts sync when the trail returns.</span></div></div>`;}
document.addEventListener("click",e=>{const b=e.target.closest("button");if(!b)return;if(b.dataset.route)return routeTo(b.dataset.route);if(b.dataset.set){state[b.dataset.set]=b.dataset.value;return render();}if(b.dataset.react){state.reactions[b.dataset.react]=!state.reactions[b.dataset.react];toast(`${b.dataset.react} reaction updated`);return render();}let a=b.dataset.action;if(a==="share")return toast("Share card copied as a safe preview");if(a==="appeal")return modal("Appeal score",'<p class="subtle">Explain what the scoring system missed.</p><textarea placeholder="Add appeal reason"></textarea>');if(["report","block","mute"].includes(a))return modal(a==="report"?"Report content":"Safety action",'<p class="subtle">This dummy flow records the action without exposing exact location.</p><textarea placeholder="Optional note"></textarea>');if(a==="comment")return modal("Add comment",'<textarea placeholder="Keep it helpful and safe"></textarea>');if(a==="like"){state.likes++;return toast(`Liked. ${state.likes} likes`);}if(a==="repost")return toast("Repost prepared with original attribution");if(a==="join"){state.joined=!state.joined;toast(state.joined?"Group joined":"Invite copied");return render();}if(a==="welfare"){state.welfare=!state.welfare;toast(state.welfare?"Welfare concern marked":"Welfare concern cleared");return render();}if(a==="menu")return $("#postMenu")?.classList.toggle("open");if(a==="offline")return toast("Offline mode opened. Drafts stay on this device.");if(a==="draft")return toast("Draft saved on this device");toast("Action confirmed");});
$("#modal").addEventListener("click",e=>{if(e.target.id==="modal"||e.target.closest("[data-modal-close]"))closeModal();if(e.target.closest("[data-modal-ok]")){closeModal();toast("Submitted for review");}});
window.addEventListener("hashchange",()=>{state.route=location.hash.replace("#","")||"map";render();});
state.route=location.hash.replace("#","")||"map";render();
